measures.expression:
DIVIDE (
    CALCULATE (
        [Sales QTY KG],
        QBS_SighCast_Sales[OrderType] = 0
    ),
    CALCULATE (
        DISTINCTCOUNT ( QBS_SighCast_Sales[OrderID] ),
        QBS_SighCast_Sales[OrderType] = 0
    )
)

DIVIDE(
    [Sales DCurrent Month QTY],[Sales DPrevious Month QTY] 
)

DIVIDE (
    CALCULATE (
        [SalesBeforeTax],
        QBS_SighCast_Sales[OrderType] = 0
    ),
    CALCULATE (
        DISTINCTCOUNT ( QBS_SighCast_Sales[OrderID] ),
        QBS_SighCast_Sales[OrderType] = 0
    )
)

DIVIDE (
    CALCULATE (
        COUNT ( QBS_SighCast_Sales[ItemID] ),
        QBS_SighCast_Sales[OrderType] = 0
    ),
    CALCULATE (
        DISTINCTCOUNT ( QBS_SighCast_Sales[OrderID] ),
        QBS_SighCast_Sales[OrderType] = 0
    )
)

COUNTROWS(
    FILTER(
        DateDim,
        DateDim[Date] < TODAY() && DateDim[IsWorkingDay] = TRUE()

    )
)

VAR LastDateWithData =
    CALCULATE (
        MAX ( 'QBS_SighCast_Sales'[DueDate] ),
        REMOVEFILTERS ()
    )
VAR FirstDateVisible =
    MIN ( 'DateDim'[Date] )
    // CALCULATE(
    //     MIN ( 'Sales'[SessionClosingDate] ),
    //     REMOVEFILTERS()
    // )
VAR Result =
    FirstDateVisible <= LastDateWithData
RETURN
    Result

DIVIDE (
    CALCULATE (
        COUNTROWS (
            FILTER (
                SUMMARIZE (
                    FILTER ( QBS_SighCast_Sales, QBS_SighCast_Sales[OrderType] = 0 ),
                    QBS_SighCast_Sales[CustomerNo],
                    "PurchaseCount", DISTINCTCOUNT ( QBS_SighCast_Sales[InvoiceDate] )
                ),
                [PurchaseCount] > 1
            )
        )
    ),
    CALCULATE (
        DISTINCTCOUNT ( QBS_SighCast_Sales[CustomerNo] ),
        QBS_SighCast_Sales[OrderType] = 0
    )
)

COALESCE(
COUNTROWS(
    SUMMARIZE(FILTER(
           QBS_SighCast_Visits,
            QBS_SighCast_Visits[Visit status] = "Negative"
        )
        ,
       QBS_SighCast_Visits[Customerno],
        [TripDate]
    )
),   0
)

COUNTROWS(
    SUMMARIZE(FILTER(
            QBS_SighCast_Visits,
            QBS_SighCast_Visits[Visit status] = "Positive"
        )
        ,
        QBS_SighCast_Visits[Customerno],
        [TripDate]
    )
)

if(
    ISINSCOPE('QBS_SighCast_Item'[Category2]),
    RANKX(
        ALLSELECTED('QBS_SighCast_Item'[Category2]),
        [Total Sales Value with ExchangeRate])
)

if(
    ISINSCOPE(QBS_SighCast_Item[Category3]),
    RANKX(
        ALLSELECTED(QBS_SighCast_Item[Category3]),
        [Total Sales Value with ExchangeRate])
)

CALCULATE([Total Sales Value with ExchangeRate],
ALLSELECTED('QBS_SighCast_Sales')
)

DIVIDE (
    [Total Sales Value with ExchangeRate],
    CALCULATE (
        [Total Sales Value with ExchangeRate],
        REMOVEFILTERS (
            QBS_SighCast_Item[Category1],
            QBS_SighCast_Item[ItemNameA]
        )
    )
)
